insert into public.properties (title_hu, title_en, description_hu, description_en, price, currency, size_m2, rooms, floor, listing_type, region, district, city, type, status, featured, images, video_url, lat, lng, reference_number, year_built, parking, garden, lift, balcony, ac, heating, energy_rating, condition, created_at) values
  ('Panorámás penthouse a Várhegy lábánál', 'Panoramic penthouse at the foot of Castle Hill', 'Diszkrét, tetőteraszos penthouse a Várnegyed szívében, egyedülálló Duna- és Parlament-panorámával. Privát lift, prémium burkolatok, okosotthon rendszer. Az ingatlan nem szerepel nyilvános portálokon.', 'A discreet rooftop penthouse in the heart of the Castle District with an unrivalled view of the Danube and Parliament. Private lift, premium finishes, full smart-home system. Not listed on any public portal.', 890000000, 'HUF', 214, 4, 6, 'elado', 'budapest', 'I. kerület', null, 'penthouse', 'active', true, ARRAY['https://images.unsplash.com/photo-1512917774080-9991f1c4c750?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1493809842364-78817add7ffb?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.4979, 19.0402, 'MH-1042', 2021, true, false, true, true, true, 'hoszivatyu', 'A+', 'új', '2026-06-10T09:00:00Z'),
  ('Klasszikus villa a Rózsadombon', 'Classic villa on Rózsadomb', 'Igényesen felújított, kertes villa Budapest legexkluzívabb negyedében. Úszómedence, dupla garázs, gondozott örökzöld kert, panorámás teraszok. Kiemelt diszkréció biztosított.', 'A meticulously renovated garden villa in Budapest’s most exclusive neighbourhood. Swimming pool, double garage, mature landscaped garden and panoramic terraces. Full discretion guaranteed.', 4200000, 'EUR', 410, 6, null, 'elado', 'budapest', 'II. kerület', null, 'villa', 'active', true, ARRAY['https://images.unsplash.com/photo-1613490493576-7fde63acd811?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1564013799919-ab600027ffc6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1605276374104-dee2a0ed3cd6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.5285, 19.022, 'MH-1043', 2009, true, true, false, true, true, 'gaz', 'B', 'felújított', '2026-06-12T11:30:00Z'),
  ('Eleganciás polgári lakás a Lipótvárosban', 'Elegant period apartment in Lipótváros', 'Magas belmagasságú, eredeti stukkókkal és parkettával rendelkező polgári lakás az V. kerület csendes utcájában. Műemléki környezet, prémium felújítás.', 'A high-ceilinged period apartment with original stucco and parquet on a quiet street in District V. Listed-building surroundings, premium renovation throughout.', 1200000, 'HUF', 138, 3, 2, 'kiado', 'budapest', 'V. kerület', null, 'lakás', 'active', true, ARRAY['https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600566753086-00f18fb6b3ea?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600210492486-724fe5c67fb0?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600585154526-990dced4db0d?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.5018, 19.0512, 'MH-1044', 1898, false, false, false, false, false, 'tavfutes', 'D', 'felújított', '2026-06-14T08:15:00Z'),
  ('Modern családi ház Hegyvidéken', 'Modern family house in Hegyvidék', 'Letisztult, energiatakarékos családi ház erdőszéli telken a XII. kerületben. Nagy üvegfelületek, kétszintes nappali, wellness részleg.', 'A clean-lined, energy-efficient family house on a forest-edge plot in District XII. Large glazing, double-height living room and a wellness suite.', 2650000, 'EUR', 320, 5, null, 'elado', 'budapest', 'XII. kerület', null, 'ház', 'active', false, ARRAY['https://images.unsplash.com/photo-1568605114967-8130f3a36994?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1570129477492-45c003edd2be?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1576941089067-2de3c901e126?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.4925, 18.9899, 'MH-1045', 2018, true, true, false, true, true, 'hoszivatyu', 'AA', 'új', '2026-06-09T14:45:00Z'),
  ('Dunai panorámás lakás az Újlipótvárosban', 'Danube-view apartment in Újlipótváros', 'Tágas, erkélyes lakás közvetlen Duna-panorámával, a XIII. kerület patinás Bauhaus tömbjében. Világos terek, igényes konyha.', 'A spacious balconied apartment with a direct Danube view in a fine Bauhaus block in District XIII. Bright spaces and a high-end kitchen.', 850000, 'HUF', 112, 3, 4, 'kiado', 'budapest', 'XIII. kerület', null, 'lakás', 'active', false, ARRAY['https://images.unsplash.com/photo-1502005229762-cf1b2da7c5d6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1493809842364-78817add7ffb?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1556909114-f6e7ad7d3136?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1567767292278-a4f21aa2d36e?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.5266, 19.0503, 'MH-1046', 1936, false, false, true, true, false, 'gaz', 'C', 'felújított', '2026-06-05T10:00:00Z'),
  ('Tetőtéri penthouse a Belvárosban', 'Top-floor penthouse in Downtown', 'Kétszintes, panorámateraszos penthouse a Belváros szívében. Privát lift, klimatizált terek, exkluzív közös tetőkert.', 'A two-storey penthouse with a panoramic terrace in the heart of Downtown. Private lift, climate-controlled spaces and an exclusive shared roof garden.', 4500, 'EUR', 186, 4, 7, 'kiado', 'budapest', 'V. kerület', null, 'penthouse', 'active', false, ARRAY['https://images.unsplash.com/photo-1512917774080-9991f1c4c750?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1493809842364-78817add7ffb?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1502672260266-1c1ef2d93688?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1560448204-e02f11c3d0e2?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.4956, 19.0533, 'MH-1047', 2016, true, false, true, true, true, 'elektromos', 'A', 'új', '2026-06-01T16:20:00Z'),
  ('Erdőszéli villatelek a Hűvösvölgyben', 'Forest-edge villa plot in Hűvösvölgy', 'Beépíthető, közművesített villatelek panorámás fekvéssel a II. kerület zöldövezetében. Kiváló befektetés diszkrét értékesítéssel.', 'A buildable, fully serviced villa plot with a panoramic setting in the green belt of District II. An excellent investment with discreet handling.', 480000000, 'HUF', 1450, 0, null, 'elado', 'budapest', 'II. kerület', null, 'telek', 'active', false, ARRAY['https://images.unsplash.com/photo-1613490493576-7fde63acd811?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1564013799919-ab600027ffc6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1605276374104-dee2a0ed3cd6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.5403, 18.965, 'MH-1048', null, false, true, false, false, false, 'gaz', 'E', 'felújítandó', '2026-05-28T12:00:00Z'),
  ('Design lakás az Óbudai Duna-parton', 'Design apartment on the Óbuda riverfront', 'Új építésű, prémium minőségű lakás a III. kerület rakparti társasházában, panorámás közös kerttel és mélygarázzsal.', 'A newly built, premium-quality apartment in a riverfront residence in District III, with a landscaped shared garden and underground parking.', 650000, 'HUF', 96, 3, 3, 'kiado', 'budapest', 'III. kerület', null, 'lakás', 'active', false, ARRAY['https://images.unsplash.com/photo-1502005229762-cf1b2da7c5d6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1493809842364-78817add7ffb?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1556909114-f6e7ad7d3136?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1567767292278-a4f21aa2d36e?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.5615, 19.0445, 'MH-1049', 2023, true, false, true, true, true, 'hoszivatyu', 'A+', 'új', '2026-05-20T09:30:00Z'),
  ('Mediterrán villa medencével Újbudán', 'Mediterranean villa with pool in Újbuda', 'Napfényes, mediterrán hangulatú villa gondozott kerttel és fűtött medencével a XI. kerület csendes villanegyedében.', 'A sun-filled, Mediterranean-style villa with a manicured garden and heated pool in a quiet villa quarter of District XI.', 1480000, 'EUR', 278, 5, null, 'elado', 'budapest', 'XI. kerület', null, 'villa', 'active', false, ARRAY['https://images.unsplash.com/photo-1568605114967-8130f3a36994?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1570129477492-45c003edd2be?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1576941089067-2de3c901e126?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.4621, 19.0312, 'MH-1050', 2012, true, true, false, true, true, 'gaz', 'B', 'felújított', '2026-05-15T13:10:00Z'),
  ('Polgári otthon a Terézvárosban', 'Period home in Terézváros', 'Reprezentatív, körfolyosós polgári lakás az Andrássy út közelében. Magas belmagasság, eredeti részletek, csendes belső udvar.', 'A representative period apartment near Andrássy Avenue. High ceilings, original details and a quiet inner courtyard.', 550000, 'HUF', 124, 3, 1, 'kiado', 'budapest', 'VI. kerület', null, 'lakás', 'active', false, ARRAY['https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600566753086-00f18fb6b3ea?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600210492486-724fe5c67fb0?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600585154526-990dced4db0d?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.5045, 19.0662, 'MH-1051', 1905, false, false, false, false, false, 'tavfutes', 'C', 'felújítandó', '2026-05-10T11:00:00Z'),
  ('Tóparti villa Tihanyban, közvetlen vízparttal', 'Lakeside villa in Tihany with direct waterfront', 'Közvetlen vízparti, panorámás villa a tihanyi félszigeten, saját stéggel és gondozott mediterrán kerttel. Prémium nyaraló vagy egész éves otthon a Balaton legszebb pontján.', 'A waterfront panoramic villa on the Tihany peninsula with a private jetty and a manicured Mediterranean garden. A premium holiday home or year-round residence at the finest spot on Lake Balaton.', 1850000, 'EUR', 240, 5, null, 'elado', 'videk', '', 'Balaton (Tihany)', 'villa', 'active', true, ARRAY['https://images.unsplash.com/photo-1613490493576-7fde63acd811?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1564013799919-ab600027ffc6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1605276374104-dee2a0ed3cd6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&w=1600&q=80']::text[], null, 46.9136, 17.8889, 'MH-1052', 2015, true, true, false, true, true, 'hoszivatyu', 'A', 'új', '2026-06-15T10:00:00Z'),
  ('Művészvilla a szentendrei óvárosban', 'Artist’s villa in Szentendre old town', 'Hangulatos, kertes ház a szentendrei óváros macskaköves utcáiban, a Duna közelében. Egyedi, művészi belső terek, kandalló, csendes udvar.', 'A charming garden house in the cobbled streets of Szentendre old town, near the Danube. Unique artistic interiors, a fireplace and a quiet courtyard.', 900000, 'HUF', 180, 4, null, 'kiado', 'videk', '', 'Szentendre', 'ház', 'active', false, ARRAY['https://images.unsplash.com/photo-1568605114967-8130f3a36994?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1570129477492-45c003edd2be?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1576941089067-2de3c901e126?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.6694, 19.0708, 'MH-1053', 1992, true, true, false, false, false, 'kandallo', 'C', 'felújított', '2026-06-08T13:00:00Z'),
  ('Polgári lakás Eger történelmi belvárosában', 'Period apartment in Eger’s historic centre', 'Felújított, boltíves polgári lakás Eger barokk belvárosában, a vár és a bazilika közelében. Eredeti részletek, magas belmagasság.', 'A renovated, vaulted period apartment in Eger’s baroque centre, near the castle and basilica. Original details and high ceilings.', 95000000, 'HUF', 102, 3, 1, 'elado', 'videk', '', 'Eger', 'lakás', 'active', false, ARRAY['https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600566753086-00f18fb6b3ea?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600210492486-724fe5c67fb0?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600585154526-990dced4db0d?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.9026, 20.3772, 'MH-1054', 1910, false, false, false, false, false, 'tavfutes', 'D', 'felújított', '2026-06-03T09:00:00Z'),
  ('Prémium nyaraló a Balaton-felvidéken', 'Premium holiday home in the Balaton uplands', 'Új építésű, igényes nyaraló panorámás telken Balatonfüred felett, medencével és nagy teraszokkal. Pár perc a parttól.', 'A newly built, refined holiday home on a panoramic plot above Balatonfüred, with a pool and large terraces. Minutes from the shore.', 720000, 'EUR', 120, 4, null, 'elado', 'videk', '', 'Balaton (Balatonfüred)', 'nyaraló', 'active', false, ARRAY['https://images.unsplash.com/photo-1568605114967-8130f3a36994?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1570129477492-45c003edd2be?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1576941089067-2de3c901e126?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600596542815-ffad4c1539a9?auto=format&fit=crop&w=1600&q=80']::text[], null, 46.9606, 17.8889, 'MH-1055', 2019, true, true, false, true, true, 'hoszivatyu', 'A', 'új', '2026-06-16T09:00:00Z'),
  ('Reprezentatív iroda a Lipótvárosban', 'Representative office in Lipótváros', 'Igényesen felújított, klimatizált irodaszint az V. kerület szívében, kiváló tömegközlekedéssel és mélygarázzsal.', 'A tastefully renovated, air-conditioned office floor in the heart of District V, with excellent transport links and underground parking.', 1500000, 'HUF', 180, 6, 3, 'kiado', 'budapest', 'V. kerület', null, 'iroda', 'active', false, ARRAY['https://images.unsplash.com/photo-1502005229762-cf1b2da7c5d6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1493809842364-78817add7ffb?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1556909114-f6e7ad7d3136?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1567767292278-a4f21aa2d36e?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.5025, 19.0512, 'MH-1056', 2008, true, false, true, false, true, 'tavfutes', 'B', 'felújított', '2026-06-13T09:00:00Z'),
  ('Utcafronti üzlethelyiség az Erzsébetvárosban', 'Street-front retail unit in Erzsébetváros', 'Forgalmas helyen fekvő, kirakatos üzlethelyiség a VII. kerületben, vendéglátásra és kiskereskedelemre egyaránt alkalmas.', 'A shop-window retail unit on a busy street in District VII, suitable for hospitality and retail alike.', 900000, 'HUF', 85, 2, 0, 'kiado', 'budapest', 'VII. kerület', null, 'üzlethelyiség', 'active', false, ARRAY['https://images.unsplash.com/photo-1600607687939-ce8a6c25118c?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600566753086-00f18fb6b3ea?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600210492486-724fe5c67fb0?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600585154526-990dced4db0d?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.4979, 19.0662, 'MH-1057', 1900, false, false, false, false, true, 'gaz', 'D', 'új', '2026-06-11T09:00:00Z'),
  ('Társasház-építésre alkalmas fejlesztési terület', 'Development site suitable for a residential building', 'Kiváló adottságú, társasház-építésre alkalmas fejlesztési terület a XXII. kerületben, érvényes szabályozási tervvel. Diszkrét értékesítés.', 'A well-positioned development site suitable for a residential building in District XXII, with a valid zoning plan. Discreet sale.', 650000000, 'HUF', 3200, 0, null, 'elado', 'budapest', 'XXII. kerület', null, 'fejlesztési terület', 'active', false, ARRAY['https://images.unsplash.com/photo-1613490493576-7fde63acd811?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1564013799919-ab600027ffc6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1605276374104-dee2a0ed3cd6?auto=format&fit=crop&w=1600&q=80','https://images.unsplash.com/photo-1600585154340-be6161a56a0c?auto=format&fit=crop&w=1600&q=80']::text[], null, 47.4264, 19.03, 'MH-1058', null, false, true, false, false, false, 'gaz', 'E', 'felújítandó', '2026-06-07T09:00:00Z')
